// Regenerates src/scanner/fingerprint/xiaomiProducts.generated.ts from the
// Home Assistant ecosystem's xiaomi-ble library (Apache-2.0), which maps the
// MiBeacon product ID — broadcast in cleartext in 0xFE95 service data even by
// devices with encrypted telemetry — to a product name and model.
//
//   node scripts/generate-xiaomi-products.mjs
//
// Commit the regenerated file.
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const SOURCE =
  'https://raw.githubusercontent.com/Bluetooth-Devices/xiaomi-ble/main/src/xiaomi_ble/devices.py';
const OUT = join(
  dirname(fileURLToPath(import.meta.url)),
  '..',
  'src',
  'scanner',
  'fingerprint',
  'xiaomiProducts.generated.ts'
);

const res = await fetch(SOURCE);
if (!res.ok) throw new Error(`Failed to fetch ${SOURCE}: ${res.status}`);
const source = await res.text();

const entries = [];
const entryPattern =
  /0x([0-9A-Fa-f]+):\s*DeviceEntry\(\s*name="([^"]+)",\s*model="([^"]+)",(?:\s*manufacturer="([^"]+)",)?/g;
for (const match of source.matchAll(entryPattern)) {
  entries.push({
    productId: parseInt(match[1], 16),
    name: match[2],
    model: match[3],
    manufacturer: match[4] ?? 'Xiaomi',
  });
}
if (entries.length < 60) {
  throw new Error(`Parsed only ${entries.length} entries — source format likely changed.`);
}

const lines = entries
  .sort((a, b) => a.productId - b.productId)
  .map(
    (entry) =>
      `  ${entry.productId}: ${JSON.stringify(`${entry.manufacturer} ${entry.name} (${entry.model})`)},`
  );

const contents = `// AUTO-GENERATED by scripts/generate-xiaomi-products.mjs — DO NOT EDIT BY HAND.
// Source: Bluetooth-Devices/xiaomi-ble (Apache-2.0). Regenerate with:
// node scripts/generate-xiaomi-products.mjs

// Xiaomi MiBeacon product IDs (from 0xFE95 service data) mapped to
// "Manufacturer Product (model)" labels.
export const XIAOMI_PRODUCTS: Record<number, string> = {
${lines.join('\n')}
};
`;

writeFileSync(OUT, contents);
console.log(`Wrote ${OUT}: ${entries.length} Xiaomi products.`);
